#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 64) {
        std::sort(arr.begin(), arr.end());
        return;
    }
    auto b = arr.begin(), e = arr.end(), it = std::is_sorted_until(b, e);
    if (it != e) {
        auto ir = b + 1;
        while (ir != e && ir[-1] >= ir[0]) ++ir;
        if (ir > it) { std::reverse(b, ir); it = ir; }
    }
    if (it == e) return;
    if (it - b > (ptrdiff_t)(n / 4) || e - it < 128) {
        std::sort(it, e);
        std::inplace_merge(b, it, e);
    } else {
        auto s = e - 1;
        while (s != b && s[-1] <= s[0]) --s;
        if (e - s > (ptrdiff_t)(n / 4)) {
            std::sort(b, s);
            std::inplace_merge(b, s, e);
        } else std::sort(b, e);
    }
}

